solution_code:
#include <iostream>

constexpr int power(int base, int exp) {
    int result = 1;
    for (int i = 0; i < exp; ++i)
        result *= base;
    return result;
}

int main() {
    constexpr int ct = power(2, 10);
    std::cout << "Compile-time: " << ct << "\n";

    int base, exp;
    std::cin >> base >> exp;
    std::cout << "Runtime: " << power(base, exp) << "\n";
    return 0;
}

